module top_module(
    input [15:0] signal_inverted,
    output reg [1:0] output_signal
);always @(*) begin
    if (signal_inverted < 1000) begin
        output_signal = 2'b01;
    end else if (signal_inverted >= 1000 && signal_inverted <= 2000) begin
        output_signal = 2'b10;
    end else if (signal_inverted > 2000) begin
        output_signal = 2'b11;
    end
end

endmodule
